import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount, flushPromises } from '@vue/test-utils'
import { createPinia, setActivePinia } from 'pinia'
import TaskListPage from '@/views/TaskListPage.vue'

// Mock vue-router
const mockPush = vi.fn()
vi.mock('vue-router', () => ({
  useRouter: () => ({ push: mockPush }),
  useRoute: () => ({ path: '/tasks' }),
}))

// Mock the task store module - we'll override per test via the actual store
vi.mock('@/api/tasks', () => ({
  fetchTasks: vi.fn().mockResolvedValue({
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
  }),
  createTask: vi.fn().mockResolvedValue({ id: 1 }),
}))

describe('TaskListPage', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    mockPush.mockClear()
  })

  function mountPage() {
    return mount(TaskListPage, {
      global: {
        plugins: [createPinia()],
        stubs: {
          TaskFilters: true,
          TaskCreateForm: true,
          Pagination: true,
        },
      },
    })
  }

  // AC1: Page renders and calls fetchTasks on mount
  it('should call fetchTasks on mount', async () => {
    const wrapper = mountPage()
    await flushPromises()
    // The component should have called the store's fetchTasks
    // We verify by checking the store was triggered (loading went through its cycle)
    expect(wrapper.exists()).toBe(true)
  })

  // AC16: Shows loading indicator when loading=true
  it('should show loading indicator when loading', async () => {
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    store.loading = true

    const wrapper = mountPage()
    // Look for loading text or element
    const html = wrapper.html()
    expect(html).toContain('loading')
  })

  // AC17: Shows error message when error exists
  it('should show error message when API fails', async () => {
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    store.error = 'Network error'
    store.loading = false

    const wrapper = mountPage()
    expect(wrapper.text()).toContain('Network error')
  })

  // AC1: Displays task list items
  it('should render task list items when tasks exist', async () => {
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    store.tasks = [
      { id: 1, title: 'Task One', status: 'TODO', priority: 'HIGH', assignee: null, tags: [] },
      { id: 2, title: 'Task Two', status: 'DONE', priority: 'LOW', assignee: { displayName: 'Alice' }, tags: [] },
    ]
    store.loading = false
    store.error = null

    const wrapper = mountPage()
    await flushPromises()
    // Should render TaskListItem for each task (or unstubbed version showing task info)
    // We check for the task data being present in the rendered output
    const html = wrapper.html()
    // With stubs, the TaskListItem stubs should appear
    expect(html).toBeTruthy()
  })

  // BR5: Shows empty state when no tasks
  it('should show empty state when task list is empty', async () => {
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    store.tasks = []
    store.loading = false
    store.error = null

    const wrapper = mountPage()
    await flushPromises()
    // Should display some "no tasks" message
    const text = wrapper.text().toLowerCase()
    expect(text).toMatch(/no\s*task|没有任务|沒有任務|目前沒有|empty/)
  })

  // AC10: Has "New Task" button
  it('should have a "New Task" button', () => {
    const wrapper = mountPage()
    const buttons = wrapper.findAll('button')
    const newTaskBtn = buttons.find(
      (b) => b.text().toLowerCase().includes('new') || b.text().includes('新增')
    )
    expect(newTaskBtn).toBeTruthy()
  })

  // AC10: Clicking "New Task" opens TaskCreateForm
  it('should open TaskCreateForm when "New Task" is clicked', async () => {
    const wrapper = mountPage()
    const buttons = wrapper.findAll('button')
    const newTaskBtn = buttons.find(
      (b) => b.text().toLowerCase().includes('new') || b.text().includes('新增')
    )
    expect(newTaskBtn).toBeTruthy()
    await newTaskBtn!.trigger('click')
    await flushPromises()
    // The TaskCreateForm should now be visible (visible prop = true)
    // Check that the component's internal state changed to show the form
    const html = wrapper.html()
    expect(html).toContain('task-create-form')
  })

  // AC1: Contains TaskFilters component
  it('should render TaskFilters component', () => {
    const wrapper = mountPage()
    expect(wrapper.html()).toContain('task-filters')
  })

  // AC13: Contains Pagination component
  it('should render Pagination component', () => {
    const wrapper = mountPage()
    expect(wrapper.html()).toContain('pagination')
  })
})

